import React, { useState, useEffect, useRef } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const ReelsFeed = () => {
  const { user } = useAuth();
  const [reels, setReels] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [liked, setLiked] = useState({});
  const videoRefs = useRef([]);
  const containerRef = useRef(null);

  useEffect(() => {
    fetchReels();
  }, []);

  useEffect(() => {
    // Auto-play current video when scrolled into view
    if (videoRefs.current[currentIndex]) {
      const ref = videoRefs.current[currentIndex];
      if (ref.tagName === 'VIDEO') {
        ref.play().catch(() => {});
      }
    }
  }, [currentIndex]);

  const fetchReels = async () => {
    try {
      // Fetch both user uploads and TMDB trailers
      const [userReelsRes, tmdbReelsRes] = await Promise.all([
        api.get('/reels').catch(() => ({ data: [] })),
        api.get('/movie-reels').catch(() => ({ data: [] }))
      ]);

      const userReels = (userReelsRes.data || []).map(reel => ({
        ...reel,
        type: 'user',
        id: reel._id
      }));

      const tmdbReels = (tmdbReelsRes.data || []).map(reel => ({
        ...reel,
        type: 'tmdb'
      }));

      // Combine and interleave: 2 TMDB trailers, then 1 user reel, repeat
      const combined = [];
      let userIdx = 0;
      let tmdbIdx = 0;

      while (userIdx < userReels.length || tmdbIdx < tmdbReels.length) {
        // Add up to 2 TMDB trailers
        if (tmdbIdx < tmdbReels.length) combined.push(tmdbReels[tmdbIdx++]);
        if (tmdbIdx < tmdbReels.length) combined.push(tmdbReels[tmdbIdx++]);

        // Add 1 user reel
        if (userIdx < userReels.length) combined.push(userReels[userIdx++]);
      }

      setReels(combined);
    } catch (error) {
      console.error('Error fetching reels:', error);
      setReels([]);
    } finally {
      setLoading(false);
    }
  };

  const handleScroll = (e) => {
    const scrollTop = e.target.scrollTop;
    const height = e.target.clientHeight;
    const newIndex = Math.round(scrollTop / height);

    if (newIndex !== currentIndex && newIndex < reels.length && newIndex >= 0) {
      // Pause previous video if it's a user upload
      if (videoRefs.current[currentIndex]?.tagName === 'VIDEO') {
        videoRefs.current[currentIndex].pause();
      }
      setCurrentIndex(newIndex);
    }
  };

  const handleLike = async (reel) => {
    try {
      if (reel.type === 'user') {
        await api.post(`/reels/${reel._id}/like`);
        setLiked((prev) => ({ ...prev, [reel._id]: !prev[reel._id] }));
        setReels(reels.map(r =>
          r._id === reel._id ? { ...r, likes: r.likes + 1 } : r
        ));
      } else {
        // For TMDB reels, just track locally
        setLiked((prev) => ({ ...prev, [reel.id]: !prev[reel.id] }));
      }
    } catch (error) {
      console.error('Error liking reel:', error);
    }
  };

  const handleShare = (reel) => {
    let text = '';
    let url = '';

    if (reel.type === 'user') {
      text = `Check out this movie edit: "${reel.title}"`;
      url = window.location.origin;
    } else {
      text = `Check out ${reel.title} - trailer on Cineverse!`;
      url = reel.trailerKey ? `https://www.youtube.com/watch?v=${reel.trailerKey}` : window.location.origin;
    }

    if (navigator.share) {
      navigator.share({
        title: 'Movie Reel',
        text,
        url
      }).catch(() => {});
    } else {
      navigator.clipboard.writeText(`${text} ${url}`);
      alert('Share link copied to clipboard!');
    }
  };

  if (loading) {
    return (
      <div className="h-screen flex items-center justify-center bg-black text-white">
        <div className="flex flex-col items-center gap-4">
          <div className="w-10 h-10 border-2 border-purple-500 border-t-transparent rounded-full animate-spin" />
          <p className="text-gray-400 text-sm">Loading reels...</p>
        </div>
      </div>
    );
  }

  if (reels.length === 0) {
    return (
      <div className="h-screen flex items-center justify-center bg-black text-white">
        <div className="text-center">
          <div className="text-4xl mb-4">🎬</div>
          <p className="text-gray-400 mb-4">No reels yet</p>
          {user && (
            <p className="text-sm text-gray-500">Be the first to upload a movie edit!</p>
          )}
        </div>
      </div>
    );
  }

  const currentReel = reels[currentIndex];
  const isUserReel = currentReel.type === 'user';

  return (
    <div
      ref={containerRef}
      className="h-screen overflow-y-scroll snap-y snap-mandatory bg-black"
      onScroll={handleScroll}
    >
      {reels.map((reel, index) => {
        const isUser = reel.type === 'user';

        return (
          <div
            key={isUser ? reel._id : reel.id}
            className="h-screen snap-start relative flex items-center justify-center bg-black"
          >
            {/* Background blur for TMDB trailers */}
            {!isUser && index === currentIndex && (
              <div
                className="absolute inset-0 bg-center bg-cover blur-2xl opacity-30"
                style={{ backgroundImage: `url(${reel.backdrop || reel.poster})` }}
              />
            )}

            {/* Video/Trailer Content */}
            {isUser ? (
              // User-uploaded video
              <video
                ref={(el) => (videoRefs.current[index] = el)}
                className="h-full w-full object-contain relative"
                src={`http://localhost:5000${reel.videoUrl}`}
                loop
                playsInline
                muted={index !== currentIndex}
              />
            ) : (
              // TMDB trailer (YouTube embed)
              index === currentIndex && reel.trailerKey ? (
                <iframe
                  className="relative w-full h-full sm:w-[400px] sm:h-[90vh] sm:rounded-xl"
                  src={`https://www.youtube.com/embed/${reel.trailerKey}?autoplay=1&mute=1&controls=0&loop=1&playlist=${reel.trailerKey}&modestbranding=1&rel=0&showinfo=0`}
                  title={reel.title}
                  allow="autoplay; encrypted-media"
                  allowFullScreen
                  style={{ border: 'none' }}
                />
              ) : (
                <img
                  className="relative h-full w-full object-cover sm:w-[400px] sm:h-[90vh] sm:rounded-xl"
                  src={reel.poster}
                  alt={reel.title}
                />
              )
            )}

            {/* Right side actions */}
            <div className="absolute right-4 bottom-32 flex flex-col items-center gap-5 z-20">
              {/* Like */}
              <button
                onClick={() => handleLike(reel)}
                className="flex flex-col items-center hover:scale-110 transition"
              >
                <span className={`text-3xl ${liked[isUser ? reel._id : reel.id] ? 'text-red-500' : 'text-white'}`}>
                  {liked[isUser ? reel._id : reel.id] ? '❤️' : '🤍'}
                </span>
                <span className="text-xs text-gray-300 mt-1">{isUser ? reel.likes : 0}</span>
              </button>

              {/* Share */}
              <button
                onClick={() => handleShare(reel)}
                className="flex flex-col items-center hover:scale-110 transition"
              >
                <span className="text-3xl">🔗</span>
                <span className="text-xs text-gray-300 mt-1">Share</span>
              </button>

              {/* TMDB Link (for movie trailers) */}
              {!isUser && reel.trailerKey && (
                <a
                  href={`https://www.themoviedb.org/movie/${reel.id}`}
                  target="_blank"
                  rel="noreferrer"
                  className="flex flex-col items-center hover:scale-110 transition"
                >
                  <span className="text-3xl">🎬</span>
                  <span className="text-xs text-gray-300 mt-1">TMDB</span>
                </a>
              )}

              {/* Comment */}
              <button className="flex flex-col items-center hover:scale-110 transition">
                <span className="text-3xl">💬</span>
                <span className="text-xs text-gray-300 mt-1">0</span>
              </button>

              {/* More */}
              <button className="flex flex-col items-center hover:scale-110 transition">
                <span className="text-3xl">⋯</span>
                <span className="text-xs text-gray-300 mt-1">More</span>
              </button>
            </div>

            {/* Bottom info overlay */}
            <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black/95 via-black/60 to-transparent z-10">
              <div className="max-w-sm">
                <div className="flex items-center gap-2 mb-2">
                  <h3 className="text-xl font-bold text-white">{reel.title}</h3>
                  {!isUser && <span className="text-xs bg-purple-600 px-2 py-1 rounded-full">Trailer</span>}
                  {isUser && <span className="text-xs bg-blue-600 px-2 py-1 rounded-full">Edit</span>}
                </div>

                {isUser ? (
                  <>
                    {reel.uploadedBy && (
                      <p className="text-sm text-gray-300 mb-2">
                        👤 {reel.uploadedBy.name || 'Anonymous Creator'}
                      </p>
                    )}
                    <div className="flex items-center gap-3 text-sm text-gray-400">
                      <span>👁️ {reel.views} views</span>
                      <span>•</span>
                      <span>🕐 {new Date(reel.createdAt).toLocaleDateString()}</span>
                    </div>
                  </>
                ) : (
                  <>
                    <div className="flex items-center gap-2 text-sm text-gray-300 mb-2">
                      <span>{reel.year}</span>
                      <span>•</span>
                      <span>⭐ {reel.rating}</span>
                      <span>•</span>
                      <span>{reel.genre}</span>
                    </div>
                    <p className="text-sm text-gray-400 line-clamp-2">{reel.plot}</p>
                  </>
                )}
              </div>
            </div>

            {/* Progress indicator */}
            <div className="absolute top-4 right-4 bg-black/60 px-3 py-1 rounded-full text-xs text-gray-300 z-20">
              {index + 1} / {reels.length}
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default ReelsFeed;
